import { createClient } from "@liveblocks/client";
import { createRoomContext } from "@liveblocks/react";

// Presence shape for each connected user
export type Presence = {
  color: string;
};

const client = createClient({
  authEndpoint: "/api/liveblocks-auth",
});

const {
  RoomProvider,
  useMyPresence,
  useUpdateMyPresence,
  useOthers,
  useSelf,
} = createRoomContext<Presence>(client);

export {
  RoomProvider,
  useMyPresence,
  useUpdateMyPresence,
  useOthers,
  useSelf,
};

import { Liveblocks } from "@liveblocks/node";
import { NextRequest, NextResponse } from "next/server";

const liveblocks = new Liveblocks({
  secret: process.env.LIVEBLOCKS_SECRET_KEY!,
});

export async function POST(request: NextRequest) {
  // Create a Liveblocks session for this user
  const session = liveblocks.prepareSession(`user-${Math.random().toString(36).slice(2)}`, {
    userInfo: {},
  });

  // Get the room id from the request body
  const { room } = await request.json();

  // Allow the user to enter the requested room
  session.allow(room, session.FULL_ACCESS);

  const { status, body } = await session.authorize();
  return new NextResponse(body, { status });
}

"use client";

import { ReactNode } from "react";
import { RoomProvider } from "../liveblocks.config";

const roomId = `color-picker-${process.env.NEXT_PUBLIC_ZEALT_RUN_ID}`;

export function Room({ children }: { children: ReactNode }) {
  return (
    <RoomProvider
      id={roomId}
      initialPresence={{ color: "#000000" }}
    >
      {children}
    </RoomProvider>
  );
}

"use client";

import { useUpdateMyPresence, useOthers, useSelf } from "../liveblocks.config";

export function ColorPicker() {
  const updateMyPresence = useUpdateMyPresence();
  const self = useSelf();
  const others = useOthers();

  // Build the combined list: current user first, then others
  const allUsers = [
    ...(self ? [{ connectionId: self.connectionId, color: self.presence.color ?? "#000000" }] : []),
    ...others.map((other) => ({
      connectionId: other.connectionId,
      color: other.presence.color ?? "#000000",
    })),
  ];

  function handleColorChange(e: React.ChangeEvent<HTMLInputElement>) {
    updateMyPresence({ color: e.target.value });
  }

  return (
    <div>
      <input
        id="color-input"
        type="color"
        defaultValue="#000000"
        onChange={handleColorChange}
      />
      <ul id="user-colors">
        {allUsers.map((user) => (
          <li
            key={user.connectionId}
            data-connection-id={user.connectionId}
            data-color={user.color}
            style={{ backgroundColor: user.color, width: 40, height: 40, listStyle: "none" }}
          />
        ))}
      </ul>
    </div>
  );
}

